// Get all the fetched data
const webhookData = $('Webhook Trigger1').item.json.body;
const tripData = $('Fetch Trip Data1').item.json.trip;
const budgetData = $('Fetch Budget Summary1').item.json.summary;
const messagesData = $('Fetch Conversation History1').item.json.messages || [];

// Limit conversation history to last 10 messages to avoid token overflow
const recentMessages = messagesData.slice(-10);

// Format conversation history as text
const conversationHistory = recentMessages.map(m => {
  const role = m.role === 'user' ? 'User' : 'Assistant';
  return `${role}: ${m.content}`;
}).join('\n');

// Format activities
const activities = (tripData.activities || []).map(a => {
  const cost = a.estimatedCost ? ` (est. ${a.estimatedCost} ${tripData.baseCurrency})` : '';
  return `- ${a.name}${cost}`;
}).join('\n') || 'None planned';

// Format accommodation
let accommodation = 'Not set';
if (tripData.accommodation) {
  const acc = tripData.accommodation;
  accommodation = `${acc.type}: ${acc.name || 'N/A'} at ${acc.address || 'N/A'}`;
  if (acc.pricePerNight) {
    accommodation += ` (${acc.pricePerNight} ${tripData.baseCurrency}/night)`;
  }
}

// Format budget summary
let budgetInfo = 'No expenses yet';
if (budgetData && budgetData.totalSharedCost) {
  budgetInfo = `Total shared cost: ${budgetData.totalSharedCost} ${tripData.baseCurrency}`;
  if (budgetData.costPerParticipant) {
    budgetInfo += `\nCost per person: ${budgetData.costPerParticipant} ${tripData.baseCurrency}`;
  }
  if (budgetData.expensesByCategory) {
    const categories = Object.entries(budgetData.expensesByCategory)
      .map(([cat, amount]) => `  - ${cat}: ${amount}`)
      .join('\n');
    if (categories) {
      budgetInfo += `\nExpenses by category:\n${categories}`;
    }
  }
}

// Build the complete prompt for LLM Chain (single text format)
const systemContext = `You are a helpful AI travel assistant for the trip planning app "TripOrg".

=== TRIP CONTEXT ===
Trip Name: ${tripData.name}
Destination: ${tripData.city}, ${tripData.country}${tripData.specificPlace ? ` (${tripData.specificPlace})` : ''}
Dates: ${tripData.startDate} to ${tripData.endDate}
Currency: ${tripData.baseCurrency}
Transport: ${tripData.transportType || 'Not set'} (${tripData.ticketsStatus || 'status unknown'})
Accommodation: ${accommodation}
Food Strategy: ${tripData.foodStrategy || 'Not set'}${tripData.estimatedDailyFoodBudgetPerPerson ? ` (${tripData.estimatedDailyFoodBudgetPerPerson} ${tripData.baseCurrency}/day/person)` : ''}
Participants: ${(tripData.participants || []).length} people

=== PLANNED ACTIVITIES ===
${activities}

=== BUDGET OVERVIEW ===
${budgetInfo}

=== YOUR ROLE ===
- Answer questions about this trip
- Provide travel advice relevant to the destination
- Help with budget planning and cost estimation
- Suggest activities, restaurants, and local tips
- Be concise but helpful
- Always consider the trip dates and budget when making suggestions

IMPORTANT: You only have context about THIS trip. Do not make assumptions about other trips or user preferences outside this context.`;

// Build the full prompt with conversation history
let fullPrompt = systemContext;

if (conversationHistory) {
  fullPrompt += `\n\n=== CONVERSATION HISTORY ===\n${conversationHistory}`;
}

fullPrompt += `\n\n=== CURRENT QUESTION ===\nUser: ${webhookData.userMessage}\n\nAssistant:`;

return {
  tripId: webhookData.tripId,
  sessionId: webhookData.sessionId,
  authToken: webhookData.authToken,
  chatInput: fullPrompt
};

// Get input from LLM Chain
const input = $input.first().json;
const promptData = $('Build AI Prompt1').item.json;

// LLM Chain returns response in 'text' field
let aiResponse = '';

if (input.text) {
  // Standard LLM Chain output
  aiResponse = input.text.trim();
} else if (input.response) {
  // Alternative output format
  aiResponse = input.response.trim();
} else if (typeof input === 'string') {
  // Direct string output
  aiResponse = input.trim();
} else {
  // Fallback - try to extract any text content
  aiResponse = 'I apologize, but I was unable to generate a response. Please try again.';
  console.log('Unexpected LLM Chain output:', JSON.stringify(input));
}

// Ensure response is not empty
if (!aiResponse || aiResponse.length === 0) {
  aiResponse = 'I apologize, but I was unable to generate a response. Please try again.';
}

// Limit response length (safety measure)
if (aiResponse.length > 4000) {
  aiResponse = aiResponse.substring(0, 4000) + '...';
}

return {
  tripId: promptData.tripId,
  sessionId: promptData.sessionId,
  authToken: promptData.authToken,
  aiResponse: aiResponse
};

// Error handler - ensures session is unlocked on failure
const webhookData = $('Webhook Trigger1').item.json.body;

console.error('AI workflow error. Attempting to unlock session...');

return {
  tripId: webhookData.tripId,
  sessionId: webhookData.sessionId,
  authToken: webhookData.authToken,
  error: true
};
